var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"레지나, 아빠는 호수를 찾으러 가셨다고 몇 번이나 말했잖니.","JPN":"レジーナ、お父様は湖を探しに行ったって何度も言ったでしょう。","ENG":"Regina, how many times do I have to tell you? Dad has gone looking for the Lake.","TWN":"蕾佳娜，我說了好幾次，爸爸去找湖了吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"호수 얘기는 이제 듣기 싫어! 아빠 보고 싶단 말이야!","JPN":"湖の話なんてもう聞きたくない！　パパに会いたいの！","ENG":"I don't want to hear about the Lake anymore! I miss Dad!","TWN":"我不想再聽湖的事情了！我想見爸爸！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"소란 떨지 말렴.","JPN":"大声を出さないでちょうだい。","ENG":"Don't be such a crybaby.","TWN":"不可以大吵大鬧的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"넌 학회의 후계자야. 품위를 지켜야지.","JPN":"あなたは学会の後継者なのよ。品位を保たないと。","ENG":"You're the heir of the Society. Behave yourself.","TWN":"妳是學會的繼承者，必須要保持禮儀。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"아빠?","JPN":"パパ？","ENG":"Dad?","TWN":"爸爸？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마, 아빠가 왔나 봐!","JPN":"ママ！　パパが来たみたい！","ENG":"Mom, Dad's home!","TWN":"媽媽，爸爸好像回來了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"기다려, 아빠! 내가 지금 문 열어 줄게!","JPN":"待って、パパ！　私が今門を開けてあげるから！","ENG":"Wait, Dad! I'm coming to the door!","TWN":"等等，爸爸！我現在就幫你開門！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OCTOPUS_ESPR_NULL_NULL","text":{"KOREA":"레...... 지나......","JPN":"レ……ジーナ……","ENG":"Re... gina...","TWN":"蕾……佳娜……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉......?!","JPN":"ひッ……！？","ENG":"Hic...","TWN":"咿……？！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OCTOPUS_ESPR_NULL_NULL","text":{"KOREA":"아빠...... 아빠란다...... 내...... 딸......","JPN":"パパ……パパだよ……レ……ジーナ……","ENG":"It's Daddy... It's your Daddy... my baby...","TWN":"爸爸……是爸爸啊……我的……女兒……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OCTOPUS_ESPR_NULL_NULL","text":{"KOREA":"레...... 지나...... 호수를...... 찾아선 안...... 돼......","JPN":"レジ……ナ……湖を……探しては……いけな…………","ENG":"Regina... You must... not... find... the lake...","TWN":"蕾……佳娜……不能去……找……湖……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어, 어머니? 지금...... 뭘 하시는 거죠?","JPN":"お、お母様？　……何をしているの？","ENG":"M-Mother? What... are you doing?","TWN":"母、母親？您……在做什麼？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_01"},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마 아버지를...... 아버지를 잡아먹는 건가요......?","JPN":"まさか、お父様を……食べてるの……？","ENG":"You're not... You're not feeding on Father, are you?","TWN":"您該不會……把父親吃掉了……？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_02"},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"이건 이제 네 아버지가 아냐. 학회를 배신한 변절자일 뿐이지.","JPN":"これはもうあなたの父じゃないの。学会の裏切者よ。","ENG":"This isn't your father anymore. It's a filthy traitor who turned his back on the Society.","TWN":"他現在不是妳的父親了，他只是個背叛學會的叛徒而已。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"다 <color=#ff3636>네 아</color>비 탓이야. 그 더러<color=#ff3636>운 피</color>가 네게도 열등한 기<color=#ff3636>질을 물</color>려 주고 말았어.","JPN":"全<color=#ff3636>てはあなたの父</color>親のせいよ。その汚<color=#ff3636>い血</color>のせいで、あなたも卑しい気<color=#ff3636>質を受け</color>継いでしまったの。","ENG":"This is all <color=#ff3636>your fa</color>ther's fault. His dir<color=#ff3636>ty</color>, impure blood runs in you veins... He left his in<color=#ff3636>feriorities</color> within you!","TWN":"都是<color=#ff3636>妳父</color>親的錯。他那<color=#ff3636>骯髒的血</color>液，讓妳都染上了劣<color=#ff3636>等的氣</color>質。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_02"},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"더러운 건 당신이겠지!","JPN":"汚いのはあなたよ！","ENG":"You're the dirty one!","TWN":"骯髒的是妳吧！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전부 알고 있어! 당신이 지하실에서 무슨 짓을 저질렀는지!","JPN":"何もかも知ってるの！　あなたが地下室で何をしたのか！","ENG":"I know everything! I know what you did in the basement!","TWN":"我全都知道！妳在地下室做了些什麼事！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"내 두 눈으로 똑똑히 봤다고!","JPN":"私はこの目で見たんだから！","ENG":"I saw with my own eyes!","TWN":"我用這雙眼清楚地看到了！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"위대한 지<color=#ff3636>식을 탐</color>구하기 위한 제<b>물</b>이지.","JPN":"偉大なる知<color=#ff3636>識を探</color>求するための供<b>物</b>よ。","ENG":"It was a sacri<b>fice</b> that had to be made in our journey to attain the great know<color=#ff3636>ledge</color>.","TWN":"這是為了追求偉大知<color=#ff3636>識</color>的祭<b>品</b>啊。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"오<color=#ff3636>히려</color> 그 천<b>한 것</b>이 내게 감사해야 할 걸?","JPN":"む<color=#ff3636>しろ、</color> あの卑し<b>い者</b>が私に感謝すべきだわ。","ENG":"That riff-<b>raff</b> should be grate<color=#ff3636>ful</color>!","TWN":"反<color=#ff3636>而是</color>那個卑<b>劣的東</b>西該感謝我才對吧？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 입 닥쳐!","JPN":"黙れ！","ENG":"Shut your mouth!","TWN":"閉嘴！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신 같은 괴물들이 망가뜨린 거야! 그 사람은......!","JPN":"あなたのような怪物たちがメチャクチャにしたの！　あの人は……！","ENG":"It was monsters like you that destroyed...","TWN":"是妳這怪物毀掉的！那個人……！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 사람은......","JPN":"あの人は……","ENG":"destroyed...","TWN":"那個人是……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"......누구였지?","JPN":"……誰だった？","ENG":"Who was it?","TWN":"……是誰？"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"깼어? 피곤하면 좀 더 자 두는 게 어때?","JPN":"起きた？　疲れてるなら、もう少し寝てたら？","ENG":"Are you awake? You look tired. Why don't you go back to sleep?","TWN":"妳醒了？累的話就再睡一下吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아지트에서 나오자마자 픽 쓰러지더라고.","JPN":"アジトから出るなりバッタリ倒れたの、憶えてる？","ENG":"You collapsed the moment we got out of the hideout.","TWN":"從據點出來後，妳馬上就昏過去了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"몸이 얼음장 같아서 죽은 줄 알았지 뭐야.","JPN":"身体が氷みたいに冷たかったから死んだかと思ったよ。","ENG":"You felt so cold that I thought you were dead.","TWN":"妳的身體冷冰冰的，我還以為妳死掉了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델......","JPN":"エデル……","ENG":"Edel...","TWN":"艾瑟兒……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델은 어떻게 됐나요? 다시 날뛰지는 않던가요?","JPN":"エデルはどうなったのです？　また暴れたりしていませんか？","ENG":"What happened to Edel? Did she go into a frenzy again?","TWN":"艾瑟兒怎麼樣了？她沒有再亂來吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하. 아직 잠이 덜 깼나 보네. 에델은 네 무릎을 베고 누워 계십니다요.","JPN":"アハ。まだ寝ぼけてるみたいだね。エデルはアンタの膝を枕にして寝てるよ。","ENG":"Aha. You're still sleep-drunk. Edel's sound asleep with her head on your lap.","TWN":"啊哈，看來妳還沒睡醒呢，艾瑟兒正枕在妳膝蓋上呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"몸에 생채기 하나 없네요.","JPN":"体に傷一つありませんね。","ENG":"She doesn't have a single scratch on her.","TWN":"她身上一點傷痕也沒有呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 커다란 쇳덩어리로 몇 번을 꿰뚫렸는데......","JPN":"あんなに大きな鉄の塊で何度も貫かれたのに……","ENG":"She doesn't look like someone who had huge metal stakes pierced through her body.","TWN":"明明被那個巨大的鐵塊貫穿了好幾次……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hngh...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일어났어요? 몸은 좀 괜찮나요?","JPN":"目が覚めましたか？　体調はいかがですか？","ENG":"Are you awake? How are you feeling?","TWN":"妳起來了？身體沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 아프지는 않아요. 머리는 조금 멍해도 무척 개운한 기분이네요.","JPN":"ええ。痛みはありません。頭は少しぼうっとしていますが、とてもスッキリした気分です。","ENG":"It's okay. A little woozy, but refreshed.","TWN":"嗯，沒有痛的地方。腦袋雖然有點暈，但感覺很清爽。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런데...... 혹시 저희가 무슨 결례를 저지르진 않았나요?","JPN":"ところで……我々が何か失礼なことをしませんでしたか？","ENG":"Um... We didn't cause any trouble back there, did we?","TWN":"不過……我們是不是做了什麼失禮的事情？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니라고는 못하겠네요. 당신 그림자에서 나온 것들에게 잡아 먹힐 뻔했거든요.","JPN":"していないとは言えませんね。あなたの影から出てきたモノに食べられそうになりましたから。","ENG":"I can't say you didn't. We almost got eaten by the things that came out of your shadow.","TWN":"無法否定呢。我差點被妳影子裡冒出的東西吃掉了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그랬군요......","JPN":"そうでしたか……","ENG":"Oh...","TWN":"原來如此……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"죄송해요. 요즘 들어 허기를 주체하기 어려워서요.","JPN":"すみません。最近、飢えを抑えるのが難しくなっていて……","ENG":"Sorry. It's been particularly difficult to contain our hunger these days.","TWN":"真是對不起。我們最近很難抑制饑餓。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"배가 고프다고 앞뒤 안 가리면 안 되죠. 그런 안일한 태도는 숙녀로서 실격이에요.","JPN":"空腹だからと正気を失っていては困ります。あのような安易な行動は淑女としても失格ですわ。","ENG":"You can't just go munching on anything just because you're hungry. As a lady, you should refrain from such careless behavior.","TWN":"不可以因為飢餓就變得不顧一切，這種隨便的態度作為淑女是失格的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럴 수가...... 저희는 꽤 조신한 편이라고 생각했는데......","JPN":"そんな……我々はかなりお淑やかだと思っていたのですが……","ENG":"No... We thought we were behaving modestly...","TWN":"怎麼會……我們還以為我們很克制了呢……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"저기, 숙녀 운운하기 전에 인간으로서 실격 아닐까?","JPN":"ねえ、淑女がどうこう言う前に、人間として失格なんじゃない？","ENG":"Erm, are you sure it's not as a human being that she should refrain from doing such a thing?","TWN":"那個，在淑女失格之前，她已經是人類失格了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 좀 가만히 있어요. 그 입 얼려 버리기 전에.","JPN":"あなたは黙っていてください。その口を凍らせますわよ？","ENG":"Just stay quiet, will you? Or I'll freeze your tongue.","TWN":"妳給我安靜地待著。不然我就把妳的嘴巴凍起來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"네, 네. 그래얍죠.","JPN":"はいはい、わかりましたよ。","ENG":"Yeah, yeah. Whatever you want.","TWN":"是，是，遵命。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델, 리벳이 당신을 따라다니는 이유는 아지트에서 들었어요.","JPN":"エデル、リベットがあなたについて回る理由はアジトで聞きましたわ。","ENG":"Rivet told me why she has been following you around, Edel.","TWN":"艾瑟兒，我在基地里聽里維說了她跟著你的理由。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇지만 전 여전히 당신에 대해 아무것도 몰라요.","JPN":"でも、私はあなたについて、相変わらずなにも知りません。","ENG":"But there are so many things I don't know about you,","TWN":"但我對妳還是一無所知。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가령...... 당신 그림자 안에 도사리고 있는 그 기묘한 것들 말이죠.","JPN":"たとえば……あなたの影の中でうごめいている、あの奇妙なモノたちについて。","ENG":"such as those odd things lurking in your shadow.","TWN":"比如……潛藏在妳的影子中，那些奇怪的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대답해 줘요. 그건 대체 뭐죠?","JPN":"答えてください。あれは何なのですか？","ENG":"Tell me, please. What are they?","TWN":"回答我，那到底是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아, 그런 질문이라면 얼마든지 대답해 드릴 수 있어요.","JPN":"ああ、そのような質問ならいくらでもお答えできますよ。","ENG":"Ah, that's a question that can be easily answered.","TWN":"啊，如果是這種問題，不管幾個我都可以回答您。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"차기 학회장이 되기로 하셨으니, 차근차근 알아 나가시는 편이 좋겠죠.","JPN":"次期学会長になると約束してくださいましたし、少しずつ知っていかれた方が良いでしょう。","ENG":"You've decided to become the next President of the Society. It's important that you learn these things, one by one.","TWN":"既然您已經決定成為下任學會長，還是慢慢瞭解會比較好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 아이들이 바로 <color=#ffd34c>지식의 호수</color>예요.","JPN":"この子たちこそが<color=#ffd34c>知識の湖</color>なんです。","ENG":"They are the <color=#ffd34c>Lake of Knowledge</color>.","TWN":"這些孩子就是<color=#ffd34c>知識之湖</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};